const config = $('Set Config').first().json;
const filePath = config.file_path;
const baseTitle = config.title;
const category = config.category;
const source = config.source;
const chunkSize = Number(config.chunk_size || 1200);
const chunkOverlap = Number(config.chunk_overlap || 200);

const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
const text = buffer.toString('utf8').replace(/\r\n/g, '\n').trim();

if (!text) {
  return [];
}

const items = [];
let chunkIndex = 1;
let start = 0;

while (start < text.length) {
  const end = Math.min(start + chunkSize, text.length);
  const chunkText = text.slice(start, end).trim();

  if (chunkText) {
    items.push({
      json: {
        source,
        category,
        title: `${baseTitle} :: chunk ${String(chunkIndex).padStart(2, '0')}`,
        content: chunkText,
        tags: ['openbrain', 'file_ingest'],
        metadata_json: {
          file_path: filePath,
          chunk_index: chunkIndex,
          chunk_start: start,
          chunk_end: end,
          chunk_size: chunkSize,
          chunk_overlap: chunkOverlap,
          total_chars: text.length
        }
      }
    });
  }

  if (end >= text.length) {
    break;
  }

  start = end - chunkOverlap;
  chunkIndex += 1;
}

return items;

const totalChunks = items.length;
const ingestedAt = new Date().toISOString();

return items.map((item) => {
  const filePath = item.json?.metadata_json?.file_path || $('Set Config').first().json.file_path || '';
  const filename = filePath.split('/').pop() || filePath;
  const chunkIndex = Number(item.json?.metadata_json?.chunk_index || 1);

  return {
    json: {
      ...item.json,
      metadata_json: {
        filename,
        chunk_index: chunkIndex,
        total_chunks: totalChunks,
        ingested_at: ingestedAt,
      },
    },
  };
});
